/**
 * @description Type for Guid value.
 * @public
 */
export type ɵGuid = string;

/**
 * @public
 * @description Empty Guid constant.
 */
export const ɵEMPTY_GUID = '00000000-0000-0000-0000-000000000000';

/**
 * @description Regular expression for Guid validation.
 * @public
 */
const validator = new RegExp('^[a-z0-9]{8}-[a-z0-9]{4}-[a-z0-9]{4}-[a-z0-9]{4}-[a-z0-9]{12}$', 'i');

/**
 * @description Generates guid part.
 * @param length Part length.
 * @public
 */
function generateGuidPart(length: number): string {
	let out = '';
	for (let i = 0; i < length; i++) {
		// eslint-disable-next-line no-bitwise
		out += (((1 + Math.random()) * 0x10000) | 0).toString(16).substring(1);
	}
	return out;
}

/**
 * @description Generates new Guid.
 * @public
 */
export function ɵgenerateGuid(): ɵGuid {
	return [
		generateGuidPart(2),
		generateGuidPart(1),
		generateGuidPart(1),
		generateGuidPart(1),
		generateGuidPart(3),
	].join('-');
}

/**
 * @description Checks if value is Guid.
 * @param value Value for check.
 * @public
 */
export function ɵisGuid(value: unknown): boolean {
	return Boolean(value) && validator.test(value as string);
}

/**
 * @description Checks if Guid is empty value or equal to EMPTY_GUID.
 * @param guid Guid for check.
 * @public
 */
export function ɵisEmptyGuid(guid: ɵGuid | undefined): boolean {
	return !guid || guid === ɵEMPTY_GUID;
}
