import { Exclude } from 'class-transformer';

import { ɵencodeDate } from '../../../../../external/utils';
import { ɵDataValueType } from '../../../../../public/enums';
import { ɵLookupValue } from '../../../../../public/models';
import { ɵEntityColumnValue, ɵJsonObject } from '../../../../../public/types';
import { ɵExpressionType } from '../../enums';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression, ɵExpressionConfig } from '../base-expression';

/**
 * @public
 * @description Configuration of parametric expression.
 */
export type ɵParameterExpressionConfig = ɵExpressionConfig<ɵParameterExpression> & Pick<ɵParameterExpression, 'value'>;

/**
 * @public
 * @description The class that defines the parametric expression.
 * @extends {ɵBaseExpression}
 */
export class ɵParameterExpression extends ɵBaseExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_ParameterExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Type of expression.
	 */
	public readonly expressionType: ɵExpressionType = ɵExpressionType.Parameter;

	/**
	 * @description Parameter value.
	 */
	@Exclude()
	public readonly value: ɵEntityColumnValue;

	/**
	 * @description Parameter value type.
	 */
	@Exclude()
	public readonly dataValueType: ɵDataValueType;

	/**
	 * @description Parameter object reference.
	 */
	public readonly parameter: {
		value?: ɵEntityColumnValue;
		arrayValue?: string[];
		dataValueType: ɵDataValueType;
	};

	constructor(config: ɵParameterExpressionConfig) {
		super(config);
		const value = config?.value;
		if (value instanceof Date) {
			const cloneDate = new Date();
			cloneDate.setTime(value.getTime());
			this.value = cloneDate;
		} else if (!value) {
			this.value = value;
		} else {
			this.value = typeof value === 'object' ? { ...(value as ɵLookupValue) } : value;
		}
		this.dataValueType = config?.dataValueType ?? ɵDataValueType.Text;
		this.parameter = {
			dataValueType: this.dataValueType,
			...this._getParameterValueMetadata(),
		};
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson(dto: ɵJsonObject): ɵParameterExpression {
		const expression = new ɵParameterExpression(dto['parameter'] as unknown as ɵParameterExpressionConfig);
		return expression;
	}

	private _convertStringToBlobArray(str: string): string[] {
		const out: string[] = [];
		let position = 0;
		for (let i = 0; i < str.length; i++) {
			const code = str.charCodeAt(i);
			if (code < 128) {
				out[position++] = String.fromCharCode(code);
			} else if (code < 2048) {
				/* eslint-disable no-bitwise */
				out[position++] = String.fromCharCode((code >> 6) | 192);
				out[position++] = String.fromCharCode((code & 63) | 128);
			} else {
				out[position++] = String.fromCharCode((code >> 12) | 224);
				out[position++] = String.fromCharCode(((code >> 6) & 63) | 128);
				out[position++] = String.fromCharCode((code & 63) | 128);
				/* eslint-enable no-bitwise */
			}
		}
		return out;
	}

	private _getParameterValueMetadata(): {
		value?: ɵEntityColumnValue;
		arrayValue?: string[];
	} {
		if (this.dataValueType === ɵDataValueType.Blob) {
			return {
				arrayValue: !this.value ? [] : this._convertStringToBlobArray(this.value as string),
			};
		} else if (this.value instanceof Date) {
			return {
				value: ɵencodeDate(this.value),
			};
		} else {
			return {
				value: this.value,
			};
		}
	}

	/**
	 * @description Returns cloned instance.
	 */
	public clone(): ɵParameterExpression {
		return new ɵParameterExpression(this);
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [];
	}
}
