import { classToPlain } from 'class-transformer';

import { ɵQueryOperationType } from './query-operation-type';
import { ɵValidationUtilities } from '../../../exceptions';
import { ɵMetadataProvider } from '../metadata-provider/metadata-provider';

/**
 * @public
 * @description The base class of the data request. Implements {@link ɵMetadataProvider}
 */
export abstract class ɵBaseQuery implements ɵMetadataProvider<Record<string, unknown>> {
	// region Constructors: Protected

	protected constructor(public readonly operationType: ɵQueryOperationType, public readonly rootSchemaName: string) {
		ɵValidationUtilities.checkArgumentEmpty('_operationType', operationType);
		ɵValidationUtilities.checkArgumentEmpty('_rootSchemaName', rootSchemaName);
	}

	// endregion

	// region Methods: Public

	/** {@inheritDoc ɵMetadataProvider.getMetadata} */
	public getMetadata(): Record<string, unknown> {
		return classToPlain(this, { exposeUnsetFields: false, excludePrefixes: ['_'] });
	}

	// endregion
}
