import { ɵBaseFilterParser } from './base-filter-parser';
import { ɵFilterResolver } from './filter-resolver';
import { ɵJsonObject } from '../../../../types';
import { ɵFilterType } from '../../enums';
import { ɵExpressionParser } from '../../expressions/expression-parser/expression-parser';
import { ɵBaseFilter } from '../base-filter';

/**
 * @public
 * @description Filter parser.
 */
export class ɵFilterParser extends ɵBaseFilterParser {
	/**
	 * @description Creates filter from JSON.
	 * @param dto - Serialized filter.
	 */
	public static fromJson(dto: ɵJsonObject): ɵBaseFilter {
		const filterType = dto['filterType'] as ɵFilterType;
		const isEnabled = dto['isEnabled'] as boolean;
		const trimDateTimeParameterToDate = dto['trimDateTimeParameterToDate'] as boolean;
		const filter = ɵFilterResolver.resolve(filterType).fromJson(dto, ɵFilterParser, ɵExpressionParser);
		filter.isEnabled = isEnabled !== false;
		filter.trimDateTimeParameterToDate = trimDateTimeParameterToDate === true;
		return filter;
	}
}
