import { Exclude, Expose } from 'class-transformer';

import { ɵBaseFilter } from './base-filter';
import { ɵBetweenFilter } from './between-filter';
import { ɵCompareFilter } from './compare-filter';
import { ɵExistsFilter } from './exists-filter';
import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵInFilter } from './in-filter';
import { ɵIsNullFilter } from './isnull-filter';
import { ɵEntityColumnValue, ɵgenerateGuid, ɵGuid, ɵJsonObject } from '../../../../public/types';
import { ɵValidationUtilities } from '../../../exceptions';
import { ɵComparisonType } from '../enums/comparison-type.enum';
import { ɵFilterType } from '../enums/filter-type.enum';
import { ɵLogicalOperatorType } from '../enums/logical-operator-type.enum';
import { ɵQueryMacrosType } from '../enums/query-macros-type.enum';
import { ɵColumnExpression } from '../expressions/columns/column-expression';
import { ɵMacrosFunctionExpression } from '../expressions/functions/macros-function-expression';
import { ɵParameterExpression } from '../expressions/parameters/parameter-expression';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description Group of filters. Groups of filters can be nested into each other,
 * i.e. The collection itself can be an element of another collection.
 * @extends {ɵBaseFilter}
 */
export class ɵFilterGroup extends ɵBaseFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_FilterGroup';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseFilter._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @public
	 * @description Collection of child filters.
	 */
	@Exclude()
	public filters = new Map<ɵGuid, ɵBaseFilter>();

	/**
	 * @public
	 * @description Return collecion of deserialized filters.
	 */
	@Expose()
	public get items(): { [key: string]: ɵBaseFilter } {
		const result = {};
		this.filters.forEach((filter, key) => {
			result[key] = this.serializeItem(filter);
		});
		return result;
	}

	/**
	 * @description The type of the logical operation for a combination of filters in the collection.
	 */
	public logicalOperation: ɵLogicalOperatorType;
	/**
	 * @description Root schema name.
	 */
	public rootSchemaName?: string;

	constructor(logicalOperation = ɵLogicalOperatorType.And, rootSchemaName?: string) {
		super(ɵFilterType.FilterGroup);
		this.logicalOperation = logicalOperation;
		this.rootSchemaName = rootSchemaName;
	}

	/**
	 * @public
	 * @description Parses filter group from json.
	 */
	public static fromJson<T extends typeof ɵBaseFilterParser>(dto: ɵJsonObject, filterParser: T): ɵFilterGroup {
		const logicalOperation = dto['logicalOperation'] as ɵLogicalOperatorType;
		const group = new ɵFilterGroup(logicalOperation || ɵLogicalOperatorType.And, dto['rootSchemaName'] as string);
		Object.entries(dto['items'] as ɵJsonObject).forEach(([key, filterDTO]) => {
			group.add(filterParser.fromJson(filterDTO as ɵJsonObject) as ɵBaseFilter, key);
		});
		return group;
	}

	/** {@inheritDoc ɵSerializable.toJson} */
	public toJson(): ɵJsonObject {
		const result = {};
		result['filterType'] = this.filterType;
		result['isEnabled'] = this.isEnabled;
		result['logicalOperation'] = this.logicalOperation;
		result['trimDateTimeParameterToDate'] = this.trimDateTimeParameterToDate;
		result['items'] = this.items;
		if (this.rootSchemaName) {
			result['rootSchemaName'] = this.rootSchemaName;
		}
		return result;
	}

	private _createParameterValueExpressions(values: ɵEntityColumnValue[]): ɵParameterExpression[] {
		return values.map(
			(value) =>
				new ɵParameterExpression({
					value: value,
				}),
		);
	}

	/**
	 * @public
	 * @description Returns filter item by index.
	 * @param index Item index.
	 * @returns Filter.
	 */
	public getItemByIndex(index: number): ɵBaseFilter {
		return this.items[Object.keys(this.items)[index]];
	}

	/**
	 * @public
	 * @description Creates and adds compare filter by value.
	 * @param comparisonType Comparison type.
	 * @param columnPath Column path.
	 * @param parameterValue Parameter value.
	 * @param filterKey Filter key.
	 */
	public addSchemaColumnFilterWithParameter(
		comparisonType: ɵComparisonType,
		columnPath: string,
		parameterValue: ɵEntityColumnValue,
		filterKey?: string,
	): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const rightExpression = new ɵParameterExpression({ value: parameterValue });
		const filter = new ɵCompareFilter(comparisonType, leftExpression, rightExpression);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds in filter by values.
	 * @param comparisonType Comparison type.
	 * @param columnPath Column path.
	 * @param parameterValues Parameter values.
	 * @param filterKey Filter key.
	 */
	public addSchemaColumnInFilterWithParameters(
		comparisonType: ɵComparisonType,
		columnPath: string,
		parameterValues: ɵEntityColumnValue[],
		filterKey?: string,
	): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const expressions = this._createParameterValueExpressions(parameterValues);
		const filter = new ɵInFilter(comparisonType, leftExpression, expressions);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds in filter for primary column.
	 * @param primaryColumnValues Primary column values.
	 * @param filterKey Filter key.
	 */
	public addPrimarySchemaColumnInFilter(primaryColumnValues: ɵEntityColumnValue[], filterKey?: string): void {
		const leftExpression = new ɵMacrosFunctionExpression({ macrosType: ɵQueryMacrosType.PrimaryColumn });
		const expressions = this._createParameterValueExpressions(primaryColumnValues);
		const filter = new ɵInFilter(ɵComparisonType.Equal, leftExpression, expressions);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds null filter.
	 * @param columnPath Path of column.
	 * @param filterKey Filter key.
	 */
	public addSchemaColumnIsNullFilter(columnPath: string, filterKey?: string): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const filter = new ɵIsNullFilter(ɵComparisonType.Is_null, leftExpression);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds not null filter.
	 * @param columnPath Column path.
	 * @param filterKey Filter key.
	 */
	public addSchemaColumnIsNotNullFilter(columnPath: string, filterKey?: string): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const filter = new ɵIsNullFilter(ɵComparisonType.Is_not_null, leftExpression);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds filter between less value and greater value.
	 * @param columnPath Column path.
	 * @param lessParamValue Less parameter value.
	 * @param greaterParamValue Greater parameter value.
	 * @param filterKey Filter key.
	 */
	public addSchemaColumnBetweenFilterWithParameters(
		columnPath: string,
		lessParamValue: Date | number,
		greaterParamValue: Date | number,
		filterKey?: string,
	): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const rightLessExpression = new ɵParameterExpression({ value: lessParamValue });
		const rightGreaterExpression = new ɵParameterExpression({ value: greaterParamValue });
		const filter = new ɵBetweenFilter(leftExpression, rightLessExpression, rightGreaterExpression);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds exists filter.
	 * @param columnPath Column path.
	 * @param subFilters Filters for exists expression.
	 * @param filterKey Filter key.
	 */
	public addExistsFilter(columnPath: string, subFilters?: ɵFilterGroup, filterKey?: string): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const filter = new ɵExistsFilter(leftExpression, <ɵFilterGroup>subFilters);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Creates and adds not exists filter.
	 * @param columnPath Column path.
	 * @param subFilters Filters for exist expression.
	 * @param filterKey Filter key.
	 */
	public addNotExistsFilter(columnPath: string, subFilters?: ɵFilterGroup, filterKey?: string): void {
		const leftExpression = new ɵColumnExpression({ columnPath });
		const filter = new ɵExistsFilter(leftExpression, <ɵFilterGroup>subFilters, ɵComparisonType.Not_exists);
		this.add(filter, filterKey);
	}

	/**
	 * @public
	 * @description Adds filter.
	 * @param filter Instance of filter.
	 * @param filterKey Filter key.
	 */
	public add(filter: ɵBaseFilter, filterKey?: string): void {
		ɵValidationUtilities.checkArgumentEmpty('filter', filter);
		const key = filterKey || ɵgenerateGuid();
		this.filters.set(key, filter);
	}

	/**
	 * @public
	 * @description Clones instance.
	 */
	public clone(): ɵFilterGroup {
		const filterGroup = new ɵFilterGroup(this.logicalOperation, this.rootSchemaName);
		this.filters.forEach((filter, filterKey) => {
			filterGroup.filters.set(filterKey, filter.clone());
		});
		filterGroup.isEnabled = this.isEnabled;
		filterGroup.trimDateTimeParameterToDate = this.trimDateTimeParameterToDate;
		return filterGroup;
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		const result: UsedColumn[] = [];
		this.filters.forEach((filter) => {
			let filterUsedColumns = filter._getUsedColumns ? filter._getUsedColumns() : [];
			filterUsedColumns = filterUsedColumns.map((usedColumn) => ({
				path: usedColumn.path,
				schemaName: usedColumn.schemaName ?? this.rootSchemaName,
			}));
			result.push(...filterUsedColumns);
		});
		return result;
	}
}
