import { classToPlain } from 'class-transformer';

import { ɵFilterType } from '../../enums';
import { UsedColumn } from '../../used-column';
import { ɵBaseFilter } from '../base-filter';

export class ɵFilterMock extends ɵBaseFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_FilterMock';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseFilter._instanceOfKeys, this._instanceOfKey];
	}

	constructor(filterType: ɵFilterType = ɵFilterType.None) {
		super(filterType);
	}

	// eslint-disable-next-line @typescript-eslint/ban-types
	public get plainObject(): object {
		return classToPlain(this, { exposeUnsetFields: false, excludePrefixes: ['_'] });
	}

	public clone(): ɵFilterMock {
		return new ɵFilterMock(this.filterType);
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [];
	}
}
