import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵExpressionType } from '../../enums';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression, ɵExpressionConfig } from '../base-expression';

/**
 * @public
 * @description Configuration of expression of type column EntitySchema.
 */
export type ɵColumnExpressionConfig = ɵExpressionConfig<ɵColumnExpression> & Pick<ɵColumnExpression, 'columnPath'>;

/**
 * @public
 * @description A class that defines an expression of type column EntitySchema.
 * @extends {ɵBaseExpression}
 */
export class ɵColumnExpression extends ɵBaseExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_ColumnExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Type of expression.
	 */
	public readonly expressionType: ɵExpressionType = ɵExpressionType.SchemaColumn;

	/**
	 * @description The path to the column is relative to root schema. Elements of the path are separated by a dot.
	 */
	public columnPath: string;

	constructor(config: ɵColumnExpressionConfig) {
		super(config);
		this.columnPath = config?.columnPath;
	}

	/**
	 * Parses expression from json.
	 * @public
	 * @param dto - Serialized object.
	 */
	public static fromJson(dto: ɵJsonObject): ɵColumnExpression {
		const expression = new ɵColumnExpression({ columnPath: dto['columnPath'] as string });
		return expression;
	}

	/**
	 * @description Clones instance.
	 */
	public clone(): ɵColumnExpression {
		return new ɵColumnExpression(this);
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [
			{
				path: this.columnPath,
			},
		];
	}
}
