import { ɵFilterType } from '../../enums/filter-type.enum';
import { ɵBaseFilter } from '../base-filter';
import { ɵBetweenFilter } from '../between-filter';
import { ɵCompareFilter } from '../compare-filter';
import { ɵExistsFilter } from '../exists-filter';
import { ɵFilterGroup } from '../filter-group';
import { ɵInFilter } from '../in-filter';
import { ɵIsNullFilter } from '../isnull-filter';

/**
 * @public
 * @description Filter resolver.
 */
export class ɵFilterResolver {
	/**
	 * @public
	 * @description Resolves class of filter.
	 * @param filterType - Type of filter.
	 * @return Class of filter.
	 */
	public static resolve(filterType: ɵFilterType): typeof ɵBaseFilter {
		const filterClass = {
			[ɵFilterType.Compare]: ɵCompareFilter,
			[ɵFilterType.FilterGroup]: ɵFilterGroup,
			[ɵFilterType.In]: ɵInFilter,
			[ɵFilterType.IsNull]: ɵIsNullFilter,
			[ɵFilterType.Exists]: ɵExistsFilter,
			[ɵFilterType.Between]: ɵBetweenFilter,
		};
		return filterClass[filterType];
	}
}
