function isHistoricalDate(date: Date): boolean {
	return date.getFullYear() < 1970;
}

function getISOStringWithOffset(date: Date): string {
	const timeZoneOffset = date.getTimezoneOffset() * 60000;
	return new Date(date.getTime() - timeZoneOffset).toISOString().slice(0, -1);
}

function getISOStringForPre1970Date(date: Date): string {
	const year = date.getFullYear();
	const month = padToTwoDigits(date.getMonth() + 1);
	const day = padToTwoDigits(date.getDate());
	const hours = padToTwoDigits(date.getHours());
	const minutes = padToTwoDigits(date.getMinutes());
	const seconds = padToTwoDigits(date.getSeconds());
	const milliseconds = padToThreeDigits(date.getMilliseconds());
	return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}.${milliseconds}`;
}

function padToTwoDigits(value: number): string {
	return String(value).padStart(2, '0');
}

function padToThreeDigits(value: number): string {
	return String(value).padStart(3, '0');
}

/**
 * @public
 * Returns a string represent of date in ISO 8601 without time zone specification(doesn't convert it
 * using local timezone).
 *
 * Example:
 *
 *      const date = new Date(2018, 01, 20, 15, 10, 30);
 *      const result = toLocalISOString(date);
 *      //result: '2018-02-20T15:10:30'
 *
 * @param date Date value.
 */
export function ɵtoLocalISOString(date: Date): string {
	if (!(date instanceof Date)) {
		throw new TypeError();
	}
	return isHistoricalDate(date) ? getISOStringForPre1970Date(date) : getISOStringWithOffset(date);
}

/**
 * @public
 * Returns encoded date in string value.
 * @param date Date value.
 */
export function ɵencodeDate(date: Date): string {
	return `"${ɵtoLocalISOString(date)}"`;
}
