import { classToPlain } from 'class-transformer';

import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵSerializable } from '../../../interfaces';
import { ɵJsonObject } from '../../../types/json-data.type';
import { ɵFilterType } from '../enums/filter-type.enum';
import { ɵBaseExpressionParser } from '../expressions/expression-parser/base-expression-parser';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @abstract
 * @description The base class of the filter.
 * @extends {ɵSerializable}
 */
export abstract class ɵBaseFilter implements ɵSerializable {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_BaseFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [this._instanceOfKey];
	}

	/**
	 * @description Type of filter.
	 */
	public readonly filterType: ɵFilterType;

	/**
	 * @description Indicates that the filter is active and will be taken into account when building the query.
	 */
	public isEnabled = true;

	/**
	 * @description Drop the time for the date / time type parameters.
	 */
	public trimDateTimeParameterToDate = false;

	/**
	 * @public
	 * @description Method for checking if an instance is of the current class type.
	 * @param instance - The instance to check.
	 * @returns `true` if the instance is of the current class type, `false` otherwise.
	 */
	public static [Symbol.hasInstance](instance: ɵBaseFilter): boolean {
		const instanceOfKeys = instance?.constructor?.['_instanceOfKeys'] ?? [];
		return instanceOfKeys.includes(this._instanceOfKey);
	}

	protected constructor(filterType: ɵFilterType) {
		this.filterType = filterType;
	}

	/**
	 * Parses filter from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser: TExpressionParser): ɵBaseFilter {
		throw new Error(`fromJson not supported on filter type ${this.constructor.name}`);
	}

	protected serializeItem(item: ɵSerializable): ɵJsonObject {
		return typeof item.toJson === 'function'
			? item.toJson()
			: classToPlain(item, {
					exposeUnsetFields: false,
					excludePrefixes: ['_'],
			  });
	}

	/**
	 * @public
	 * @description Clones instance.
	 */
	public abstract clone(): ɵBaseFilter;

	/**
	 * Converts instance to json object.
	 * @public
	 */
	public toJson(): ɵJsonObject {
		return classToPlain(this, {
			exposeUnsetFields: false,
			excludePrefixes: ['_'],
		});
	}

	/**
	 * @internal
	 */
	public abstract _getUsedColumns(): UsedColumn[];
}
