import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵSingleFilter } from './single-filter';
import { ɵJsonObject } from '../../../types/json-data.type';
import { ɵComparisonType, ɵFilterType } from '../enums';
import { ɵBaseExpression } from '../expressions/base-expression';
import { ɵBaseExpressionParser } from '../expressions/expression-parser/base-expression-parser';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description Filter class of the "Between" type.
 * @extends {ɵSingleFilter}
 */
export class ɵBetweenFilter extends ɵSingleFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_BetweenFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵSingleFilter._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description The initial expression of the filtering range.
	 */
	public readonly rightLessExpression: ɵBaseExpression;

	/**
	 * @description The final expression of the filtering range.
	 */
	public readonly rightGreaterExpression: ɵBaseExpression;

	constructor(
		leftExpression: ɵBaseExpression,
		rightLessExpression: ɵBaseExpression,
		rightGreaterExpression: ɵBaseExpression,
	) {
		super(ɵFilterType.Between, ɵComparisonType.Between, leftExpression);
		this.rightLessExpression = rightLessExpression?.clone();
		this.rightGreaterExpression = rightGreaterExpression?.clone();
	}

	/**
	 * Parses filter from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser: TExpressionParser): ɵBetweenFilter {
		const filter = new ɵBetweenFilter(
			expressionParser.fromJson(dto['leftExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
			expressionParser.fromJson(dto['rightLessExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
			expressionParser.fromJson(dto['rightGreaterExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
		);
		return filter;
	}

	public clone(): ɵBetweenFilter {
		const filter = new ɵBetweenFilter(this.leftExpression, this.rightLessExpression, this.rightGreaterExpression);
		filter.isEnabled = this.isEnabled;
		filter.trimDateTimeParameterToDate = this.trimDateTimeParameterToDate;
		return filter;
	}

	public toJson(): ɵJsonObject {
		return {
			...super.toJson(),
			rightLessExpression: this.serializeItem(this.rightLessExpression),
			rightGreaterExpression: this.serializeItem(this.rightGreaterExpression),
		};
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [
			...super._getUsedColumns(),
			...this.rightLessExpression._getUsedColumns(),
			...this.rightGreaterExpression._getUsedColumns(),
		];
	}
}
