import { ɵBaseFilter } from './base-filter';
import { ɵJsonObject } from '../../../types';
import { ɵComparisonType, ɵFilterType } from '../enums';
import { ɵBaseExpression } from '../expressions/base-expression';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description Basic filter class with one condition.
 * @extends {ɵBaseFilter}
 */
export abstract class ɵSingleFilter extends ɵBaseFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_SingleFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseFilter._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Type of comparison operation.
	 */
	public readonly comparisonType: ɵComparisonType;

	/**
	 * @description The test expression.
	 */
	public readonly leftExpression: ɵBaseExpression;

	protected constructor(filterType: ɵFilterType, comparisonType: ɵComparisonType, leftExpression: ɵBaseExpression) {
		super(filterType);
		this.comparisonType = comparisonType;
		this.leftExpression = leftExpression?.clone();
	}

	/** {@inheritDoc ɵSerializable.toJson} */
	public toJson(): ɵJsonObject {
		return {
			...super.toJson(),
			leftExpression: this.serializeItem(this.leftExpression),
		};
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return this.leftExpression._getUsedColumns();
	}
}
