import { ɵExpressionType, ɵFunctionType } from '../../enums';
import { ɵBaseExpression, ɵExpressionConfig } from '../base-expression';

/**
 * @public
 * @description Configuration for funcion expression.
 */
export type ɵFunctionExpressionConfig<TExpression extends ɵFunctionExpression> = Omit<
	ɵExpressionConfig<TExpression>,
	'functionType'
>;

/**
 * @public
 * @abstract
 * @description A class that describes a functional expression.
 * @extends {ɵFunctionExpression}
 */
export abstract class ɵFunctionExpression extends ɵBaseExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_FunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Expression type. Default 'Function'.
	 */
	public readonly expressionType: ɵExpressionType = ɵExpressionType.Function;

	/**
	 * @description The type of the functional expression.
	 */
	public abstract readonly functionType: ɵFunctionType;

	protected constructor(config: ɵFunctionExpressionConfig<ɵFunctionExpression>) {
		super(config);
	}

	/**
	 * @description Abstract method to create cloned instance.
	 */
	public abstract clone(): ɵFunctionExpression;
}
