import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵSingleFilter } from './single-filter';
import { ɵJsonArray, ɵJsonObject } from '../../../types/json-data.type';
import { ɵComparisonType, ɵFilterType } from '../enums';
import { ɵBaseExpression } from '../expressions/base-expression';
import { ɵBaseExpressionParser } from '../expressions/expression-parser/base-expression-parser';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description In-Filter Class
 * @extends {ɵSingleFilter}
 */
export class ɵInFilter extends ɵSingleFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_InFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵSingleFilter._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description An array of expressions that will be compared with {@link #leftExpression}.
	 */
	public readonly rightExpressions: ɵBaseExpression[];

	constructor(comparisonType: ɵComparisonType, leftExpression: ɵBaseExpression, rightExpressions: ɵBaseExpression[]) {
		super(ɵFilterType.In, comparisonType, leftExpression);
		this.rightExpressions = rightExpressions.map((expression) => expression?.clone()) ?? [];
	}

	/**
	 * @description Parses in filter from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser: TExpressionParser): ɵInFilter {
		const dtoRightExpressions = (dto['rightExpressions'] ?? []) as ɵJsonArray;
		return new ɵInFilter(
			dto['comparisonType'] as ɵComparisonType,
			expressionParser.fromJson(dto['leftExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
			dtoRightExpressions.map(
				(expression) => expressionParser.fromJson(expression as ɵJsonObject, filterParser) as ɵBaseExpression,
			),
		);
	}

	/** {@inheritDoc ɵBaseFilter.clone} */
	public clone(): ɵInFilter {
		const filter = new ɵInFilter(this.comparisonType, this.leftExpression, this.rightExpressions);
		filter.isEnabled = this.isEnabled;
		filter.trimDateTimeParameterToDate = this.trimDateTimeParameterToDate;
		return filter;
	}

	/** {@inheritDoc ɵSerializable.toJson} */
	public toJson(): ɵJsonObject {
		return {
			...super.toJson(),
			rightExpressions: this.rightExpressions.map((expression) => this.serializeItem(expression)),
		};
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		const rightExpressionsUsedColumns = this.rightExpressions
			.map((expression) => expression._getUsedColumns())
			.flat();
		return [...super._getUsedColumns(), ...rightExpressionsUsedColumns];
	}
}
