import { classToPlain } from 'class-transformer';

import { ɵBaseExpressionParser } from './expression-parser/base-expression-parser';
import { ɵSerializable } from '../../../interfaces';
import { ɵJsonObject } from '../../../types/json-data.type';
import { ɵExpressionType } from '../enums/expression-type.enum';
import { ɵBaseFilterParser } from '../filters/filter-parser/base-filter-parser';
import { UsedColumn } from '../used-column';

export type ɵExpressionConfig<TExpression extends ɵBaseExpression> = Partial<Omit<TExpression, 'expressionType'>>;

/**
 * @public
 * @abstract
 * @description The base class of the expression.
 * @extends {ɵSerializable}
 */
export abstract class ɵBaseExpression implements ɵSerializable {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_BaseExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [this._instanceOfKey];
	}

	/**
	 * @description True if expression has brackets.
	 */
	public readonly isBlock: boolean = false;

	/**
	 * @public
	 * @description Method for checking if an instance is of the current class type.
	 * @param instance - The instance to check.
	 * @returns `true` if the instance is of the current class type, `false` otherwise.
	 */
	public static [Symbol.hasInstance](instance: ɵBaseExpression): boolean {
		const instanceOfKeys = instance?.constructor?.['_instanceOfKeys'] ?? [];
		return instanceOfKeys.includes(this._instanceOfKey);
	}

	/**
	 * @description Type of expression
	 */
	public abstract readonly expressionType: ɵExpressionType;

	protected constructor(config: ɵExpressionConfig<ɵBaseExpression>) {
		this.isBlock = <boolean>config?.isBlock;
	}

	/**
	 * @public
	 * @description Parses expression from json.
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser?: TExpressionParser): ɵBaseExpression {
		throw new Error(`fromJson not supported on expression type ${this.constructor.name}`);
	}

	/**
	 * @description Converts instance to json object.
	 * @param item - The instance to serialize.
	 */
	protected serializeItem(item: ɵSerializable): ɵJsonObject {
		return typeof item.toJson === 'function'
			? item.toJson()
			: classToPlain(item, {
					exposeUnsetFields: false,
					excludePrefixes: ['_'],
			  });
	}

	/**
	 * @description Abstract method to create cloned instance.
	 */
	public abstract clone(): ɵBaseExpression;

	/**
	 * @public
	 * @description Converts instance to json object.
	 */
	public toJson(): ɵJsonObject {
		return classToPlain(this, {
			exposeUnsetFields: false,
			excludePrefixes: ['_'],
		});
	}

	/**
	 * @internal
	 */
	public abstract _getUsedColumns(): UsedColumn[];
}
