import { classToPlain } from 'class-transformer';

import { ɵExpressionType } from '../../enums';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression, ɵExpressionConfig } from '../base-expression';

/**
 * @internal
 */
export const ɵEXPRESSION_TYPE_MOCK: ɵExpressionType = 0;

export class ɵExpressionMock extends ɵBaseExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_ExpressionMock';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseExpression._instanceOfKeys, this._instanceOfKey];
	}

	public readonly expressionType: ɵExpressionType = ɵEXPRESSION_TYPE_MOCK;

	constructor(config?: ɵExpressionConfig<ɵExpressionMock>) {
		super(config || {});
	}

	// eslint-disable-next-line @typescript-eslint/ban-types
	public get plainObject(): object {
		return classToPlain(this, { exposeUnsetFields: false, excludePrefixes: ['_'] });
	}

	public clone(): ɵExpressionMock {
		return new ɵExpressionMock(this);
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [];
	}
}
