import { ɵAggregationFunctionExpression } from './aggregation-function-expression';
import { ɵArgumentFunctionExpression, ɵArgumentFunctionExpressionConfig } from './argument-function-expression';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵFunctionType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { ɵBaseExpressionParser } from '../expression-parser/base-expression-parser';

/**
 * @public
 * @description Configuration for window funcion expression.
 */
export type ɵWindowFunctionExpressionConfig = ɵArgumentFunctionExpressionConfig<ɵWindowFunctionExpression>;

/**
 * @public
 * @description A class that describes expression with window function.
 * @extends {ɵArgumentFunctionExpression}
 */
export class ɵWindowFunctionExpression extends ɵArgumentFunctionExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_WindowFunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵArgumentFunctionExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Function type.
	 */
	public readonly functionType: ɵFunctionType = ɵFunctionType.Window;

	/**
	 * @description Function argument
	 */
	public readonly functionArgument!: ɵAggregationFunctionExpression;

	constructor(config: ɵWindowFunctionExpressionConfig) {
		super(config);
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser?: TExpressionParser): ɵWindowFunctionExpression {
		const functionArgument = expressionParser?.fromJson(
			dto['functionArgument'] as ɵJsonObject,
			filterParser,
		) as ɵAggregationFunctionExpression;
		return new ɵWindowFunctionExpression({ functionArgument, isBlock: dto['isBlock'] as boolean });
	}

	/** {@inheritDoc ɵBaseExpression.clone} */
	public clone(): ɵWindowFunctionExpression {
		return new ɵWindowFunctionExpression(this);
	}
}
