import { ɵSubQueryExpression, ɵSubQueryExpressionConfig } from './sub-query-expression';
import { ɵAggregationType } from '../../../../../public/enums';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵFunctionType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';

/**
 * @public
 * @description Configuration for aggregation in sub query expression.
 */
export type ɵAggregationSubQueryExpressionConfig = ɵSubQueryExpressionConfig &
	Pick<ɵAggregationSubQueryExpression, 'aggregationType'> &
	Pick<ɵAggregationSubQueryExpression, 'functionType'>;

/**
 * @public
 * @description A class that describes expression with aggregation sub query.
 * @extends {ɵSubQueryExpression}
 */
export class ɵAggregationSubQueryExpression extends ɵSubQueryExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_AggregationSubQueryExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵSubQueryExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Aggregation type.
	 */
	public readonly aggregationType: ɵAggregationType;
	/**
	 * @description Function type.
	 */
	public readonly functionType?: ɵFunctionType;

	constructor(config: ɵAggregationSubQueryExpressionConfig) {
		super(config);
		this.aggregationType = config?.aggregationType;
		this.functionType = config?.functionType;
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<TFilterParser extends typeof ɵBaseFilterParser>(
		dto: ɵJsonObject,
		filterParser: TFilterParser,
	): ɵAggregationSubQueryExpression {
		const subQueryExpression = super.fromJson(dto, filterParser) as ɵSubQueryExpression;
		const expression = new ɵAggregationSubQueryExpression({
			aggregationType: dto['aggregationType'] as ɵAggregationType,
			functionType: dto['functionType'] as ɵFunctionType,
			...subQueryExpression,
		});
		return expression;
	}

	/** {@inheritDoc ɵBaseExpression.clone} */
	public clone(): ɵAggregationSubQueryExpression {
		return new ɵAggregationSubQueryExpression(this);
	}
}
