import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵSingleFilter } from './single-filter';
import { ɵJsonObject } from '../../../types/json-data.type';
import { ɵComparisonType, ɵFilterType } from '../enums';
import { ɵBaseExpression } from '../expressions/base-expression';
import { ɵBaseExpressionParser } from '../expressions/expression-parser/base-expression-parser';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description Comparison filter class.
 * @extends {ɵSingleFilter}
 */
export class ɵCompareFilter extends ɵSingleFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_CompareFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵSingleFilter._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Filter expression.
	 */
	public readonly rightExpression: ɵBaseExpression;

	constructor(comparisonType: ɵComparisonType, leftExpression: ɵBaseExpression, rightExpression: ɵBaseExpression) {
		super(ɵFilterType.Compare, comparisonType, leftExpression);
		this.rightExpression = rightExpression?.clone();
	}

	/**
	 * Parses filter from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser: TExpressionParser): ɵCompareFilter {
		const filter = new ɵCompareFilter(
			dto['comparisonType'] as ɵComparisonType,
			expressionParser.fromJson(dto['leftExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
			expressionParser.fromJson(dto['rightExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
		);
		return filter;
	}

	public clone(): ɵCompareFilter {
		const filter = new ɵCompareFilter(this.comparisonType, this.leftExpression, this.rightExpression);
		filter.isEnabled = this.isEnabled;
		filter.trimDateTimeParameterToDate = this.trimDateTimeParameterToDate;
		return filter;
	}

	public toJson(): ɵJsonObject {
		return {
			...super.toJson(),
			rightExpression: this.serializeItem(this.rightExpression),
		};
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [...super._getUsedColumns(), ...this.rightExpression._getUsedColumns()];
	}
}
