import { ɵAggregationType } from '../../../../../public/enums';
import { ɵAggregationEvalType } from '../../enums';
import { ɵAggregationFunctionExpression, ɵBaseExpression } from '../../expressions';
import { ɵBaseQueryColumn } from '../base-query-column';

/**
 * @public
 * @classdesc Class contains info about column with aggregation function.
 * @extends {ɵBaseQueryColumn}
 */
export class ɵAggregationFunctionColumn extends ɵBaseQueryColumn<ɵAggregationFunctionExpression> {
	// region Constructors: Public

	constructor(
		aggregationType: ɵAggregationType,
		aggregationEvalType: ɵAggregationEvalType,
		functionArgument: ɵBaseExpression,
	) {
		super(
			new ɵAggregationFunctionExpression({
				aggregationType,
				aggregationEvalType,
				functionArgument,
			}),
		);
	}

	// endregion
}
