import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵSingleFilter } from './single-filter';
import { ɵJsonObject } from '../../../types';
import { ɵComparisonType, ɵFilterType } from '../enums';
import { ɵBaseExpression } from '../expressions/base-expression';
import { ɵBaseExpressionParser } from '../expressions/expression-parser/base-expression-parser';

/**
 * @public
 * @description IsNull filter Class
 * @extends {ɵSingleFilter}
 */
export class ɵIsNullFilter extends ɵSingleFilter {
	/**
	 * @description Flag that indicates if expression is empty or not.
	 */
	public isNull = true;

	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_IsNullFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵSingleFilter._instanceOfKeys, this._instanceOfKey];
	}

	constructor(
		comparisonType: ɵComparisonType.Is_null | ɵComparisonType.Is_not_null,
		leftExpression: ɵBaseExpression,
	) {
		if (![ɵComparisonType.Is_null, ɵComparisonType.Is_not_null].includes(comparisonType)) {
			console.warn(`Invalid comparison type: ${ɵComparisonType[comparisonType]} in IsNullFilter.`);
		}
		super(ɵFilterType.IsNull, ɵIsNullFilter._getComparisonType(comparisonType), leftExpression);
		this.isNull = this.comparisonType === ɵComparisonType.Is_null;
	}

	private static _getComparisonType(
		comparisonType: ɵComparisonType,
	): ɵComparisonType.Is_null | ɵComparisonType.Is_not_null {
		return comparisonType === ɵComparisonType.Is_not_null ? comparisonType : ɵComparisonType.Is_null;
	}

	/**
	 * @description Parses isNull filter from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser: TExpressionParser): ɵIsNullFilter {
		return new ɵIsNullFilter(
			ɵIsNullFilter._getComparisonType(dto['comparisonType'] as ɵComparisonType),
			expressionParser.fromJson(dto['leftExpression'] as ɵJsonObject, filterParser) as ɵBaseExpression,
		);
	}

	/** {@inheritDoc ɵBaseFilter.clone} */
	public clone(): ɵIsNullFilter {
		const filter = new ɵIsNullFilter(ɵIsNullFilter._getComparisonType(this.comparisonType), this.leftExpression);
		filter.isEnabled = this.isEnabled;
		filter.trimDateTimeParameterToDate = this.trimDateTimeParameterToDate;
		return filter;
	}
}
