import { ɵFilterGroup } from './filter-group';
import { ɵBaseFilterParser } from './filter-parser/base-filter-parser';
import { ɵSingleFilter } from './single-filter';
import { ɵJsonObject } from '../../../types';
import { ɵComparisonType, ɵFilterType } from '../enums';
import { ɵBaseExpression } from '../expressions/base-expression';
import { ɵBaseExpressionParser } from '../expressions/expression-parser/base-expression-parser';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description The comparison filter class [Exists according to the specified condition].
 * @extends {ɵSingleFilter}
 */
export class ɵExistsFilter extends ɵSingleFilter {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_ExistsFilter';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵSingleFilter._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Subquery filters. Cannot contain filters with other subqueries.
	 */
	public readonly subFilters?: ɵFilterGroup;

	/**
	 * @description Indicates that the filter is aggregating.
	 */
	public readonly isAggregative: boolean;

	constructor(
		leftExpression: ɵBaseExpression,
		subFilters?: ɵFilterGroup,
		comparisonType: ɵComparisonType = ɵComparisonType.Exists,
		isAggregative = true,
	) {
		super(ɵFilterType.Exists, comparisonType, leftExpression);
		this.subFilters = subFilters?.clone();
		this.isAggregative = isAggregative;
	}

	/**
	 * Parses filter from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser: TExpressionParser): ɵExistsFilter {
		const leftExpression = expressionParser.fromJson(
			dto['leftExpression'] as ɵJsonObject,
			filterParser,
		) as ɵBaseExpression;
		const subFiltersDto = dto['subFilters'] as ɵJsonObject;
		let subFilters;
		if (subFiltersDto) {
			subFilters = filterParser.fromJson(dto['subFilters'] as ɵJsonObject) as ɵFilterGroup;
		}
		return new ɵExistsFilter(
			leftExpression,
			subFilters,
			dto['comparisonType'] as ɵComparisonType,
			dto['isAggregative'] as boolean,
		);
	}

	/**
	 * @public
	 * @description Clones instance.
	 */
	public clone(): ɵExistsFilter {
		const filter = new ɵExistsFilter(this.leftExpression, this.subFilters, this.comparisonType, this.isAggregative);
		filter.isEnabled = this.isEnabled;
		filter.trimDateTimeParameterToDate = this.trimDateTimeParameterToDate;
		return filter;
	}

	/** {@inheritDoc ɵSerializable.toJson} */
	public toJson(): ɵJsonObject {
		const result = super.toJson();
		if (this.subFilters) {
			result['subFilters'] = this.serializeItem(this.subFilters);
		}
		return result;
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [...super._getUsedColumns(), ...(this.subFilters?._getUsedColumns() ?? [])];
	}
}
