import { ɵDatePartType } from '../../enums';
import { ɵBaseExpression, ɵDatePartFunctionExpression } from '../../expressions';
import { ɵBaseQueryColumn } from '../base-query-column';

/**
 * @public
 * @classdesc Class contains info about column with date part.
 * @extends {ɵBaseQueryColumn}
 */
export class ɵDatePartFunctionColumn extends ɵBaseQueryColumn<ɵDatePartFunctionExpression> {
	// region Constructors: Public

	constructor(datePartType: ɵDatePartType, functionArgument: ɵBaseExpression) {
		super(
			new ɵDatePartFunctionExpression({
				datePartType,
				functionArgument,
			}),
		);
	}

	// endregion

	// region Properties: Public

	/**
	 * @description Part of date.
	 */
	public get datePartType(): ɵDatePartType {
		return this.expression?.datePartType;
	}

	// endregion
}
