import { ɵOrderDirection } from '../enums';

/**
 * @internal
 */
export const ɵDEFAULT_COLUMN_PLAIN_OBJ: object = {
	isVisible: true,
	orderPosition: -1,
	orderDirection: ɵOrderDirection.None,
};

/**
 * @internal
 */
export function ɵgetColumnPlainObj(expressionPlainObj?: object): object {
	return {
		...ɵDEFAULT_COLUMN_PLAIN_OBJ,
		expression: expressionPlainObj,
	};
}
