import { ɵArithmeticOperation } from '../../enums';
import { ɵArithmeticExpression, ɵBaseExpression } from '../../expressions';
import { ɵBaseQueryColumn } from '../base-query-column';

/**
 * @public
 * @classdesc Class contains info about column with arithmetic operation.
 * @extends {ɵBaseQueryColumn}
 */
export class ɵArithmeticQueryColumn extends ɵBaseQueryColumn<ɵArithmeticExpression> {
	// region Constructors: Public

	constructor(
		arithmeticOperation: ɵArithmeticOperation,
		leftArithmeticOperand: ɵBaseExpression,
		rightArithmeticOperand: ɵBaseExpression,
	) {
		super(new ɵArithmeticExpression({ arithmeticOperation, leftArithmeticOperand, rightArithmeticOperand }));
	}

	// endregion
}
