import { ɵFunctionExpression, ɵFunctionExpressionConfig } from './function-expression';
import { ɵJsonObject } from '../../../../types';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression } from '../base-expression';

/**
 * @public
 * @description Configuration for function wih argument expression.
 */
export type ɵArgumentFunctionExpressionConfig<TExpression extends ɵArgumentFunctionExpression> =
	ɵFunctionExpressionConfig<TExpression> & Pick<ɵArgumentFunctionExpression, 'functionArgument'>;

/**
 * @public
 * @abstract
 * @description A class that describes a functional expression with argument.
 * @extends {ɵFunctionExpression}
 */
export abstract class ɵArgumentFunctionExpression extends ɵFunctionExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_ArgumentFunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵFunctionExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Expression argument.
	 */
	public readonly functionArgument: ɵBaseExpression;

	protected constructor(config: ɵArgumentFunctionExpressionConfig<ɵArgumentFunctionExpression>) {
		super(config);
		this.functionArgument = config?.functionArgument?.clone();
	}

	/**
	 * @public
	 * @description Abstract method to create cloned instance.
	 */
	public abstract clone(): ɵArgumentFunctionExpression;

	/** {@inheritDoc ɵBaseExpression.toJson} */
	public toJson(): ɵJsonObject {
		const result = super.toJson();
		if (this.functionArgument) {
			result['functionArgument'] = this.serializeItem(this.functionArgument);
		}
		return result;
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return this.functionArgument?._getUsedColumns() ?? [];
	}
}
