import { ɵViewModelContext } from '../view-model-context';

/**
 * @public
 * @description Base definition of request.
 * @template TEvent
 */
export class ɵBaseRequest<TEvent = unknown> {
	/**
	 * @public
	 * @description The type of request.
	 * @example
	 * 'crt.RequestType'
	 */
	public readonly type!: string;

	/**
	 * @deprecated use event binding expression instead.
	 */
	public readonly $initialEvent?: TEvent;

	/**
	 * @public
	 * @description The context in which the requests were triggered.
	 */
	public readonly $context!: ɵViewModelContext;

	/**
	 * @public
	 * @description The scope of the request.
	 */
	public scopes?: string[];
}
