import { ɵValidationUtilities } from '../../../../public/exceptions';
import { ɵOrderDirection } from '../enums';
import { ɵBaseExpression } from '../expressions';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @abstract
 * @classdesc Class contains info about column for query.
 */
export abstract class ɵBaseQueryColumn<TExpression extends ɵBaseExpression = ɵBaseExpression> {
	/**
	 * @description Order direction.
	 */
	public orderDirection: ɵOrderDirection = ɵOrderDirection.None;
	/**
	 * @description Column order position.
	 */
	public orderPosition = -1;
	/**
	 * @description If true then column data will be present in the result set.
	 */
	public isVisible = true;
	/**
	 * @description Column caption.
	 */
	public caption?: string;
	/**
	 * @description Column expression.
	 */
	public readonly expression: TExpression;

	protected constructor(expression: TExpression) {
		this.expression = expression;
	}

	/**
	 * Adds ordering options.
	 * @param orderDirection Direction.
	 * @param orderPosition Position.
	 * @returns Self.
	 */
	public withOrdering(orderDirection: ɵOrderDirection, orderPosition: number): this {
		ɵValidationUtilities.checkArgumentEmpty('orderDirection', orderDirection);
		ɵValidationUtilities.checkArgumentEmpty('orderPosition', orderPosition);
		ɵValidationUtilities.checkArgumentOutOfRange('orderPosition', orderPosition, { begin: -1 });
		this.orderDirection = orderDirection;
		this.orderPosition = orderPosition;
		return this;
	}

	/**
	 * Adds options.
	 * @param options Options.
	 * @returns Self.
	 */
	public withOptions(options: { isVisible?: boolean }): this {
		ɵValidationUtilities.checkArgumentEmpty('options', options);
		this.isVisible = options.isVisible ?? true;
		return this;
	}

	/**
	 * Adds caption.
	 * @param caption Caption.
	 * @returns Self.
	 */
	public withCaption(caption: string): this {
		ɵValidationUtilities.checkArgumentEmpty('caption', caption);
		this.caption = caption;
		return this;
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return this.expression._getUsedColumns();
	}
}
