import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵArithmeticOperation, ɵExpressionType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression, ɵExpressionConfig } from '../base-expression';
import { ɵBaseExpressionParser } from '../expression-parser/base-expression-parser';

/**
 * @public
 * @description Config used for arithmetic expression
 */
export type ɵArithmeticExpressionConfig = ɵExpressionConfig<ɵArithmeticExpression> &
	Pick<ɵArithmeticExpression, 'arithmeticOperation' | 'leftArithmeticOperand' | 'rightArithmeticOperand'>;

/**
 * @public
 * @description Arithmetic expression.
 * @extends {ɵBaseExpression}
 */
export class ɵArithmeticExpression extends ɵBaseExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_ArithmeticExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵBaseExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Expression type. Default 'ArithmeticOperation'.
	 */
	public readonly expressionType: ɵExpressionType = ɵExpressionType.ArithmeticOperation;
	/**
	 * @description Operation.
	 */
	public readonly arithmeticOperation: ɵArithmeticOperation;
	/**
	 * @description Left operand expression.
	 */
	public readonly leftArithmeticOperand: ɵBaseExpression;
	/**
	 * @description Right operand expression.
	 */
	public readonly rightArithmeticOperand: ɵBaseExpression;

	constructor(config: ɵArithmeticExpressionConfig) {
		super(config);
		this.arithmeticOperation = config?.arithmeticOperation;
		this.leftArithmeticOperand = config?.leftArithmeticOperand.clone();
		this.rightArithmeticOperand = config?.rightArithmeticOperand.clone();
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser?: TExpressionParser): ɵArithmeticExpression {
		const leftArithmeticOperand = expressionParser?.fromJson(
			dto['leftArithmeticOperand'] as ɵJsonObject,
			filterParser,
		) as ɵBaseExpression;
		const rightArithmeticOperand = expressionParser?.fromJson(
			dto['rightArithmeticOperand'] as ɵJsonObject,
			filterParser,
		) as ɵBaseExpression;
		const config: ɵArithmeticExpressionConfig = {
			leftArithmeticOperand,
			rightArithmeticOperand,
			arithmeticOperation: dto['arithmeticOperation'] as ɵArithmeticOperation,
			isBlock: dto['isBlock'] as boolean,
		};
		return new ɵArithmeticExpression(config);
	}

	/**
	 * @public
	 * @description Clones instance.
	 */
	public clone(): ɵArithmeticExpression {
		return new ɵArithmeticExpression(this);
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [...this.leftArithmeticOperand._getUsedColumns(), ...this.rightArithmeticOperand._getUsedColumns()];
	}
}
