import { Exclude } from 'class-transformer';

import { ɵBaseQuery } from './base-query';
import { ɵQueryOperationType } from './query-operation-type';
import { ɵFilterGroup } from '../filters/filter-group';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description The base class of the filtered data request.
 * @extends {ɵBaseQuery}
 */
export abstract class ɵBaseFilterableQuery extends ɵBaseQuery {
	/**
	 * @description Collection of filters.
	 */
	@Exclude()
	public readonly filters = new ɵFilterGroup();

	protected constructor(operationType: ɵQueryOperationType, rootSchemaName: string) {
		super(operationType, rootSchemaName);
	}

	/**
	 * @public
	 * @description Clears all filters.
	 */
	public clearFilters(): void {
		this.filters.filters.clear();
	}

	/** {@inheritDoc ɵMetadataProvider.getMetadata} */
	public getMetadata(): Record<string, unknown> {
		return {
			...super.getMetadata(),
			filters: this.filters.toJson(),
		};
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		const usedColumns = this.filters._getUsedColumns();
		usedColumns.forEach((usedColumn) => {
			if (!usedColumn.schemaName) {
				usedColumn.schemaName = this.rootSchemaName;
			}
		});
		return usedColumns;
	}
}
