import { ɵJsonObject as JsonObject } from '../../../../types/json-data.type';
import { ɵExpressionType as ExpressionType } from '../../enums';
import { ɵFilterGroup as FilterGroup } from '../../filters/filter-group';
import { ɵBaseFilterParser as BaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression as BaseExpression, ɵExpressionConfig as ExpressionConfig } from '../base-expression';

/**
 * @public
 * @description Configuration for sub query expression.
 */
export type ɵSubQueryExpressionConfig = ExpressionConfig<ɵSubQueryExpression> & Pick<ɵSubQueryExpression, 'columnPath'>;

/**
 * @public
 * @description The class that defines the sub query expression.
 * @extends {ɵBaseExpression}
 */
export class ɵSubQueryExpression extends BaseExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_SubQueryExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...BaseExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Type of expression.
	 */
	public readonly expressionType: ExpressionType = ExpressionType.SubQuery;

	/**
	 * @description The path to the column is relative to root schema.
	 */
	public columnPath: string;

	/**
	 * @description Sub-query filters. Can not contain filters with other sub-queries.
	 */
	public readonly subFilters: FilterGroup;

	/**
	 * @description Order direction.
	 */
	public readonly subOrderDirection?: number;

	/**
	 * @description Column for order.
	 */
	public readonly subOrderColumn?: string;

	constructor(config: ɵSubQueryExpressionConfig) {
		super(config);
		this.columnPath = config?.columnPath;
		const subFilters = <FilterGroup>config?.subFilters;
		if (typeof subFilters?.clone === 'function') {
			this.subFilters = subFilters.clone();
		} else if (subFilters) {
			this.subFilters = new FilterGroup(subFilters.logicalOperation, subFilters.rootSchemaName);
			Object.entries(subFilters.items).forEach(([key, filter]) => {
				this.subFilters.add(filter, key);
			});
		} else {
			this.subFilters = subFilters;
		}
		this.subOrderDirection = config.subOrderDirection;
		this.subOrderColumn = config.subOrderColumn;
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<TFilterParser extends typeof BaseFilterParser>(
		dto: JsonObject,
		filterParser: TFilterParser,
	): ɵSubQueryExpression {
		const expression = new ɵSubQueryExpression({
			columnPath: dto['columnPath'] as string,
			subFilters: filterParser.fromJson(dto['subFilters'] as JsonObject) as FilterGroup,
			subOrderDirection: dto['subOrderDirection'] as number,
			subOrderColumn: dto['subOrderColumn'] as string,
		});
		return expression;
	}

	/** {@inheritDoc ɵBaseExpression.clone} */
	public clone(): ɵSubQueryExpression {
		return new ɵSubQueryExpression(this);
	}

	/** {@inheritDoc ɵBaseExpression.toJson} */
	public toJson(): JsonObject {
		const result = super.toJson();
		if (this.subFilters) {
			result['subFilters'] = this.serializeItem(this.subFilters);
		}
		return result;
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return [
			{
				path: this.columnPath,
			},
			...(this.subFilters?._getUsedColumns() ?? []),
		];
	}
}
