import { classToPlain } from 'class-transformer';

import { ɵBaseFilterableQuery } from './base-filterable-query';
import { ɵQueryOperationType } from './query-operation-type';
import { ɵAggregationType, ɵDataValueType } from '../../../enums';
import { ɵItemNotFoundException, ɵValidationUtilities } from '../../../exceptions';
import { ɵDataSourceAggregationConfig } from '../../../services/model/data-source-aggregation-config';
import { ɵEntityColumnValue } from '../../../types';
import {
	ɵAggregationFunctionColumn,
	ɵAggregationSubQueryColumn,
	ɵArithmeticQueryColumn,
	ɵBaseQueryColumn,
	ɵDatePartFunctionColumn,
	ɵEntityQueryColumn,
	ɵLengthFunctionColumn,
	ɵMacrosFunctionColumn,
	ɵParameterQueryColumn,
	ɵWindowFunctionColumn,
} from '../columns';
import {
	eAdminUnitRoleSources,
	ɵAggregationEvalType,
	ɵArithmeticOperation,
	ɵDatePartType,
	ɵExpressionType,
	ɵQueryMacrosType,
} from '../enums';
import { ɵAggregationFunctionExpression, ɵBaseExpression, ɵColumnExpression } from '../expressions';
import { UsedColumn } from '../used-column';

/**
 * @public
 * @description Interface for condition with expression and parameter.
 * @property {ɵExpressionType} expressionType - Type of expression.
 * @property {Record<string, unknown>=} parameter - Parameter.
 */
export interface ɵConditionalValueItem {
	/**
	 * @description Type of expression.
	 */
	expressionType: ɵExpressionType;
	/**
	 * @description Parameter.
	 */
	parameter: {
		dataValueType: ɵDataValueType;
		value: string;
	};
}

/**
 * @public
 * @description The query class for data fetching.
 * @extends {ɵBaseFilterableQuery}
 */
export class ɵEntitySchemaQuery extends ɵBaseFilterableQuery {
	private _columns = new Map<string, ɵBaseQueryColumn>();

	/**
	 * @description Determines if merge duplicates in query result.
	 */
	public isDistinct = false;

	/**
	 * @description Number of rows to select.
	 */
	public rowCount = -1;

	/**
	 * @description Rows count to skip.
	 */
	public rowsOffset = -1;

	/**
	 * @description Query conditional values
	 */
	public conditionalValues?: null | { items: unknown };

	/**
	 * @description The parameter that determines whether to use the localized data.
	 */
	public useLocalization = true;

	/**
	 * @description Represent parameter which determines disabling data in filtering.
	 */
	public useRecordDeactivation = false;

	/**
	 * @description Bit mask that indicates which role sources will be considered when checking record rights.
	 */
	public adminUnitRoleSources?: eAdminUnitRoleSources;

	constructor(rootSchemaName: string) {
		super(ɵQueryOperationType.Select, rootSchemaName);
	}

	private _internalAddColumn(key: string, column: ɵBaseQueryColumn): void {
		if (!this._columns.has(key)) {
			this._columns.set(key, column);
		}
	}

	private _getIsPageable = (): boolean => this.rowCount > 0 && this.rowsOffset > -1;

	// endregion

	// region Methods: Public

	/**
	 * @public
	 * @description Returns column instance by column alias.
	 * @param columnAlias Column alias.
	 * @returns [BaseQueryColumn] Column instance.
	 */
	public getColumn(columnAlias: string): ɵBaseQueryColumn {
		if (!this._columns.has(columnAlias)) {
			throw new ɵItemNotFoundException(columnAlias);
		}
		return this.findColumn(columnAlias);
	}

	/**
	 * @public
	 * @description Returns column instance by column alias if not found returns null.
	 */
	public findColumn(columnAlias: string): ɵBaseQueryColumn {
		return this._columns.get(columnAlias) as ɵBaseQueryColumn;
	}

	/** {@inheritDoc ɵMetadataProvider.getMetadata} */
	public getMetadata(): Record<string, unknown> {
		return {
			...super.getMetadata(),
			columns: {
				items: classToPlain(this._columns, { exposeUnsetFields: false, excludePrefixes: ['_'] }),
			},
			allColumns: false,
			isDistinct: this.isDistinct,
			ignoreDisplayValues: false,
			rowCount: this.rowCount,
			rowsOffset: this.rowsOffset,
			adminUnitRoleSources: this.adminUnitRoleSources,
			isPageable: this._getIsPageable(),
			conditionalValues: this.conditionalValues ? this.conditionalValues : null,
			isHierarchical: false,
			hierarchicalMaxDepth: 0,
			hierarchicalColumnName: null,
			hierarchicalColumnValue: null,
			useLocalization: this.useLocalization,
			useRecordDeactivation: this.useRecordDeactivation,
		};
	}

	/**
	 * @public
	 * @description Add column.
	 * @param column Column path.
	 * @param columnAlias Column alias.
	 * @returns [BaseQueryColumn] Column instance.
	 */
	public addColumn(column: ɵBaseQueryColumn, columnAlias: string): ɵBaseQueryColumn {
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add column by column path.
	 * @param columnPath Column path.
	 * @param columnAlias Column alias.
	 * @returns [EntityQueryColumn] Column instance.
	 */
	public addSchemaColumn(columnPath: string, columnAlias?: string): ɵEntityQueryColumn {
		ɵValidationUtilities.checkArgumentEmpty('columnPath', columnPath);
		const column = new ɵEntityQueryColumn(columnPath);
		this._internalAddColumn(columnAlias || columnPath, column);
		return column;
	}

	/**
	 * @public
	 * @description Add aggregation sub query column.
	 * @param columnPath Column path.
	 * @param aggregationType Aggregation type.
	 * @param subFilters Sub query filters.
	 * @param columnAlias Column alias.
	 * @returns [AggregationSubQueryColumn] Column instance.
	 */
	public addAggregationSubQueryColumn(
		columnPath: string,
		aggregationType: ɵAggregationType,
		aggregationConfig: ɵDataSourceAggregationConfig,
		columnAlias?: string,
	): ɵAggregationSubQueryColumn {
		const column = new ɵAggregationSubQueryColumn(
			columnPath,
			aggregationType,
			aggregationConfig.filter,
			aggregationConfig.sortByDirection,
			aggregationConfig.sortByColumn,
		);
		this._internalAddColumn(columnAlias || columnPath, column);
		return column;
	}

	/**
	 * @public
	 * @description Add parameter column.
	 * @param value Parameter value.
	 * @param dataValueType Parameter data value type.
	 * @param columnAlias Column alias.
	 * @returns [ParameterQueryColumn] Column instance.
	 */
	public addParameterColumn(
		value: ɵEntityColumnValue,
		dataValueType: ɵDataValueType,
		columnAlias: string,
	): ɵParameterQueryColumn {
		const column = new ɵParameterQueryColumn(value, dataValueType);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add arithmetic column.
	 * @param arithmeticOperation Arithmetic operation.
	 * @param leftArithmeticOperand Left arithmetic operand expression.
	 * @param rightArithmeticOperand Right arithmetic operand expression.
	 * @param columnAlias Column alias.
	 * @returns [ArithmeticQueryColumn] Column instance.
	 */
	public addArithmeticColumn(
		arithmeticOperation: ɵArithmeticOperation,
		leftArithmeticOperand: ɵBaseExpression,
		rightArithmeticOperand: ɵBaseExpression,
		columnAlias: string,
	): ɵArithmeticQueryColumn {
		const column = new ɵArithmeticQueryColumn(arithmeticOperation, leftArithmeticOperand, rightArithmeticOperand);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add macros function column.
	 * @param queryMacrosType Macros type.
	 * @param columnAlias Column alias.
	 * @returns [MacrosFunctionColumn] Column instance.
	 */
	public addMacrosFunctionColumn(queryMacrosType: ɵQueryMacrosType, columnAlias: string): ɵMacrosFunctionColumn {
		const column = new ɵMacrosFunctionColumn(queryMacrosType);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add date part function column.
	 * @param columnPath Column path.
	 * @param datePartType Date part type.
	 * @param columnAlias Column alias.
	 * @returns [DatePartFunctionColumn] Column instance.
	 */
	public addDatePartFunctionColumn(
		columnPath: string,
		datePartType: ɵDatePartType,
		columnAlias: string,
	): ɵDatePartFunctionColumn {
		const functionArgument = new ɵColumnExpression({ columnPath });
		const column = new ɵDatePartFunctionColumn(datePartType, functionArgument);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add aggregation function column.
	 * @param columnPath Column path.
	 * @param aggregationType Aggregation type.
	 * @param columnAlias Column alias.
	 * @param aggregationEvalType Aggregation eval type.
	 * @returns [AggregationFunctionColumn] Column instance.
	 */
	public addAggregationFunctionColumn(
		columnPath: string,
		aggregationType: ɵAggregationType,
		columnAlias: string,
		aggregationEvalType: ɵAggregationEvalType = ɵAggregationEvalType.None,
	): ɵAggregationFunctionColumn {
		const functionArgument = new ɵColumnExpression({ columnPath });
		const column = new ɵAggregationFunctionColumn(aggregationType, aggregationEvalType, functionArgument);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add length function column.
	 * @param columnPath Column path.
	 * @param columnAlias Column alias.
	 * @returns [LengthFunctionColumn] Column instance.
	 */
	public addLengthFunctionColumn(columnPath: string, columnAlias: string): ɵLengthFunctionColumn {
		const functionArgument = new ɵColumnExpression({ columnPath });
		const column = new ɵLengthFunctionColumn(functionArgument);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @public
	 * @description Add window function column.
	 * @param columnPath Column path.
	 * @param aggregationType Aggregation type.
	 * @param columnAlias Column alias.
	 * @param aggregationEvalType Aggregation eval type.
	 * @returns [WindowFunctionColumn] Column instance.
	 */
	public addWindowFunctionColumn(
		columnPath: string,
		aggregationType: ɵAggregationType,
		columnAlias: string,
		aggregationEvalType: ɵAggregationEvalType = ɵAggregationEvalType.None,
	): ɵWindowFunctionColumn {
		const functionArgument = new ɵAggregationFunctionExpression({
			aggregationType,
			aggregationEvalType,
			functionArgument: new ɵColumnExpression({ columnPath }),
		});
		const column = new ɵWindowFunctionColumn(functionArgument);
		this._internalAddColumn(columnAlias, column);
		return column;
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		const usedColumns: UsedColumn[] = [];
		this._columns.forEach((column) => {
			usedColumns.push(...column._getUsedColumns());
		});
		usedColumns.forEach((usedColumn) => {
			if (!usedColumn.schemaName) {
				usedColumn.schemaName = this.rootSchemaName;
			}
		});
		return [...usedColumns, ...super._getUsedColumns()];
	}
}
