import { ɵArgumentEmptyException } from './argument-empty-exception';
import { ɵArgumentOutOfRangeException } from './argument-out-of-range-exception';

/**
 * @public
 * @description Utilities class with various validation methods.
 */
export class ɵValidationUtilities {
	// region Methods: Public

	/**
	 * @public
	 * @description Checks if argument is empty.
	 * @param argumentName - Argument name.
	 * @param argumentValue - Value of argument.
	 */
	public static checkArgumentEmpty<T>(
		argumentName: string,
		argumentValue: T | null | undefined,
	): asserts argumentValue is T {
		if (argumentValue === undefined || argumentValue === null) {
			throw new ɵArgumentEmptyException(argumentName);
		}
	}

	/**
	 * @public
	 * @description Checks if array is empty.
	 * @param argumentName - Argument name.
	 * @param argumentValue - Value of argument.
	 */
	public static checkArrayEmpty<T>(argumentName: string, argumentValue: ArrayLike<T>): void {
		ɵValidationUtilities.checkArgumentEmpty(argumentName, argumentValue);
		if (argumentValue.length === 0) {
			throw new ɵArgumentEmptyException(argumentName);
		}
	}

	/**
	 * @public
	 * @description Checks if string is empty.
	 * @param argumentName - Argument name.
	 * @param argumentValue - Value of argument.
	 */
	public static checkStringIsNotEmpty(argumentName: string, argumentValue: string): string {
		this.checkArgumentEmpty(argumentName, argumentValue);
		if (argumentValue === '') {
			throw new ɵArgumentEmptyException(argumentName);
		}
		return argumentValue;
	}

	/**
	 * @public
	 * @description Checks if argument in range.
	 * @param argumentName - Argument name.
	 * @param argumentValue - Value of argument.
	 * @param range - Range.
	 */
	public static checkArgumentOutOfRange(
		argumentName: string,
		argumentValue: number,
		range: { begin?: number; end?: number },
	): void {
		if (range.begin && argumentValue < range.begin) {
			throw new ɵArgumentOutOfRangeException(argumentName);
		}
		if (range.end && argumentValue > range.end) {
			throw new ɵArgumentOutOfRangeException(argumentName);
		}
	}

	public static checkEnumOutOfRange(
		argumentName: string,
		argumentValue: string,
		range: Record<string, unknown> | unknown,
	): void {
		if (!range || !Object.values(range).includes(argumentValue)) {
			throw new ɵArgumentOutOfRangeException(argumentName);
		}
	}

	// endregion
}
