import { ɵArgumentFunctionExpression, ɵArgumentFunctionExpressionConfig } from './argument-function-expression';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵFunctionType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { ɵColumnExpression } from '../columns/column-expression';
import { ɵBaseExpressionParser } from '../expression-parser/base-expression-parser';

/**
 * @public
 * @description Configuration of expression with length function.
 */
export type ɵLengthFunctionExpressionConfig = ɵArgumentFunctionExpressionConfig<ɵLengthFunctionExpression>;

/**
 * @public
 * @description A class that describes expression with length function.
 * @extends {ɵArgumentFunctionExpression}
 */
export class ɵLengthFunctionExpression extends ɵArgumentFunctionExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_LengthFunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵArgumentFunctionExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Function type. Default 'Length'.
	 */
	public readonly functionType: ɵFunctionType = ɵFunctionType.Length;

	/**
	 * @description Argument of function.
	 */
	public readonly functionArgument!: ɵColumnExpression;

	constructor(config: ɵLengthFunctionExpressionConfig) {
		super(config);
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser: TFilterParser, expressionParser?: TExpressionParser): ɵLengthFunctionExpression {
		const functionArgument = expressionParser?.fromJson(
			dto['functionArgument'] as ɵJsonObject,
			filterParser,
		) as ɵColumnExpression;
		return new ɵLengthFunctionExpression({ functionArgument, isBlock: dto['isBlock'] as boolean });
	}

	/**
	 * @description Method to create cloned instance.
	 */
	public clone(): ɵLengthFunctionExpression {
		return new ɵLengthFunctionExpression(this);
	}
}
