import { ɵBaseExpressionParser } from './base-expression-parser';
import { ɵExpressionResolver } from './expression-resolver';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵExpressionType } from '../../enums/expression-type.enum';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { ɵBaseExpression } from '../base-expression';

/**
 * @public
 * @description Expression parser.
 * @extends {ɵBaseExpressionParser}
 */
export class ɵExpressionParser extends ɵBaseExpressionParser {
	/**
	 * @public
	 * @description Parses expression from json.
	 */
	public static fromJson(dto: ɵJsonObject, filterParser: typeof ɵBaseFilterParser): ɵBaseExpression {
		const expressionType = dto['expressionType'] as ɵExpressionType;
		return ɵExpressionResolver.resolve(expressionType, dto).fromJson(dto, filterParser, ɵExpressionParser);
	}
}
