import { ɵAggregationType } from '../../../../../public/enums';
import { ɵAggregationSubQueryExpression } from '../../expressions';
import { ɵFilterGroup } from '../../filters';
import { ɵBaseQueryColumn } from '../base-query-column';

/**
 * @public
 * @classdesc Class contains info about column with sub query and aggregation.
 * @extends {ɵBaseQueryColumn}
 */
export class ɵAggregationSubQueryColumn extends ɵBaseQueryColumn<ɵAggregationSubQueryExpression> {
	// region Constructors: Public

	constructor(
		columnPath: string,
		aggregationType: ɵAggregationType,
		subFilters?: ɵFilterGroup,
		subOrderDirection?: number,
		subOrderColumn?: string,
	) {
		super(
			new ɵAggregationSubQueryExpression({
				aggregationType,
				columnPath,
				subFilters,
				subOrderDirection,
				subOrderColumn,
			}),
		);
	}

	// endregion
}
