import { ɵArgumentFunctionExpression, ɵArgumentFunctionExpressionConfig } from './argument-function-expression';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵDatePartType, ɵFunctionType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { ɵBaseExpression } from '../base-expression';
import { ɵBaseExpressionParser } from '../expression-parser/base-expression-parser';

/**
 * @public
 * @description Configuration for date part expression.
 */
export type ɵDatePartFunctionExpressionConfig = ɵArgumentFunctionExpressionConfig<ɵDatePartFunctionExpression> &
	Pick<ɵDatePartFunctionExpression, 'datePartType'>;

/**
 * @public
 * @description A class that describes expression part of date function.
 * @extends {ɵArgumentFunctionExpression}
 */
export class ɵDatePartFunctionExpression extends ɵArgumentFunctionExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_DatePartFunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵArgumentFunctionExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Function type. Default 'DatePart'.
	 */
	public readonly functionType: ɵFunctionType = ɵFunctionType.DatePart;

	/**
	 * @description Date part type.
	 */
	public readonly datePartType: ɵDatePartType;

	constructor(config: ɵDatePartFunctionExpressionConfig) {
		super(config);
		this.datePartType = config?.datePartType;
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(
		dto: ɵJsonObject,
		filterParser: TFilterParser,
		expressionParser?: TExpressionParser,
	): ɵDatePartFunctionExpression {
		const functionArgument = expressionParser?.fromJson(
			dto['functionArgument'] as ɵJsonObject,
			filterParser,
		) as ɵBaseExpression;
		const datePartType = dto['datePartType'] as ɵDatePartType;
		return new ɵDatePartFunctionExpression({ functionArgument, datePartType, isBlock: dto['isBlock'] as boolean });
	}

	/** {@inheritDoc ɵBaseExpression.clone} */
	public clone(): ɵDatePartFunctionExpression {
		return new ɵDatePartFunctionExpression(this);
	}
}
