import { ɵFunctionExpression, ɵFunctionExpressionConfig } from './function-expression';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵFunctionType, ɵQueryMacrosType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { UsedColumn } from '../../used-column';
import { ɵBaseExpression } from '../base-expression';
import { ɵBaseExpressionParser } from '../expression-parser/base-expression-parser';

/**
 * @public
 * @description Configuration of expression with macros function.
 */
export type ɵMacrosFunctionExpressionConfig = ɵFunctionExpressionConfig<ɵMacrosFunctionExpression> &
	Pick<ɵMacrosFunctionExpression, 'macrosType'>;

/**
 * @public
 * @description A class that describes expression with macros function.
 * @extends {ɵFunctionExpression}
 */
export class ɵMacrosFunctionExpression extends ɵFunctionExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_MacrosFunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵFunctionExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description Function type. Default 'Macros'.
	 */
	public readonly functionType: ɵFunctionType = ɵFunctionType.Macros;
	/**
	 * @description Type of macros.
	 */
	public readonly macrosType: ɵQueryMacrosType;
	/**
	 * @description Function argument.
	 */
	public readonly functionArgument?: ɵBaseExpression;

	constructor(config: ɵMacrosFunctionExpressionConfig) {
		super(config);
		this.macrosType = config?.macrosType;
		this.functionArgument = config?.functionArgument;
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(dto: ɵJsonObject, filterParser?: TFilterParser, expressionParser?: TExpressionParser): ɵMacrosFunctionExpression {
		const functionArgument =
			filterParser && expressionParser && dto['functionArgument']
				? (expressionParser.fromJson(dto['functionArgument'] as ɵJsonObject, filterParser) as ɵBaseExpression)
				: undefined;
		return new ɵMacrosFunctionExpression({ functionArgument, macrosType: dto['macrosType'] as ɵQueryMacrosType });
	}

	/**
	 * @description method to create cloned instance.
	 */
	public clone(): ɵMacrosFunctionExpression {
		return new ɵMacrosFunctionExpression(this);
	}

	/**
	 * @internal
	 */
	public _getUsedColumns(): UsedColumn[] {
		return this.functionArgument?._getUsedColumns() ?? [];
	}
}
