import { ɵArgumentFunctionExpression, ɵArgumentFunctionExpressionConfig } from './argument-function-expression';
import { ɵAggregationType } from '../../../../../public/enums';
import { ɵJsonObject } from '../../../../types/json-data.type';
import { ɵAggregationEvalType, ɵFunctionType } from '../../enums';
import { ɵBaseFilterParser } from '../../filters/filter-parser/base-filter-parser';
import { ɵBaseExpression } from '../base-expression';
import { ɵBaseExpressionParser } from '../expression-parser/base-expression-parser';

/**
 * @public
 * @description Configuration for aggregation function expression.
 */
export type ɵAggregationFunctionExpressionConfig = ɵArgumentFunctionExpressionConfig<ɵAggregationFunctionExpression> &
	Pick<ɵAggregationFunctionExpression, 'aggregationType' | 'aggregationEvalType'>;

/**
 * @public
 * @description A class that describes expression with aggregate function.
 * @extends {ɵArgumentFunctionExpression}
 */
export class ɵAggregationFunctionExpression extends ɵArgumentFunctionExpression {
	/**
	 * @internal
	 * @dontChange
	 */
	protected static readonly _instanceOfKey: string = 'devkit_AggregationFunctionExpression';

	/**
	 * @internal
	 * @dontChange
	 */
	protected static get _instanceOfKeys(): string[] {
		return [...ɵArgumentFunctionExpression._instanceOfKeys, this._instanceOfKey];
	}

	/**
	 * @description The type of the functional expression passed for initialization.
	 */
	public readonly functionType: ɵFunctionType = ɵFunctionType.Aggregation;

	/**
	 * @description Aggregation type.
	 */
	public readonly aggregationType: ɵAggregationType;

	/**
	 * @description The scope of the aggregating function.
	 */
	public readonly aggregationEvalType: ɵAggregationEvalType;

	constructor(config: ɵAggregationFunctionExpressionConfig) {
		super(config);
		this.aggregationType = config?.aggregationType;
		this.aggregationEvalType = config?.aggregationEvalType;
	}

	/**
	 * Parses expression from json.
	 * @public
	 */
	public static fromJson<
		TFilterParser extends typeof ɵBaseFilterParser,
		TExpressionParser extends typeof ɵBaseExpressionParser,
	>(
		dto: ɵJsonObject,
		filterParser: TFilterParser,
		expressionParser?: TExpressionParser,
	): ɵAggregationFunctionExpression {
		const functionArgument = expressionParser?.fromJson(
			dto['functionArgument'] as ɵJsonObject,
			filterParser,
		) as ɵBaseExpression;
		const aggregationType = dto['aggregationType'] as ɵAggregationType;
		const aggregationEvalType = dto['aggregationEvalType'] as ɵAggregationEvalType;
		return new ɵAggregationFunctionExpression({
			functionArgument,
			aggregationType,
			aggregationEvalType,
			isBlock: dto['isBlock'] as boolean,
		});
	}

	/** {@inheritDoc ɵBaseExpression.clone} */
	public clone(): ɵAggregationFunctionExpression {
		return new ɵAggregationFunctionExpression(this);
	}
}
